import * as React from 'react';
import Box from '@mui/material/Box';
import Container from '@mui/material/Container';

import ImageList from '@mui/material/ImageList';
import ImageListItem from '@mui/material/ImageListItem';

// import * as Images from '../../assets/collections/daylight/*';

function Daylight () {
	// const cache = {};

	const [cache, setCache] = React.useState([{}]);

	function importAll(r) {
		r.keys().forEach((key) => (setCache[key] = r(key)));
	};

	importAll(require.context('../../assets/collections/daylight', false, /\.jpg/));

	const images = Object.entries(cache).map(module => module[1].default);

	useEffect(() => {
		console.log(images);
	}, [])

	return (
		<>
			<Box height={'100vh'} width={'100wh'} sx={{  }}>
				{ images.map(image => (
						// <img style={{ height: '500px', width: '500px' }} src={image}/>

						<Box
							component='img'
							sx={{
								height: '300px',
								width: '200px',
							}}
							src={image}
						>
						</Box>

					))
				}
			</Box>
		</>
	)
}

export default Daylight;
